def solve(data: str) -> str:
    lines = data.strip().splitlines()
    if not lines: return ""
    n = int(lines[0])
    intervals = [list(map(int, ln.split())) for ln in lines[1:]]
    intervals.sort()
    merged = []
    for s,e in intervals:
        if not merged or s > merged[-1][1]:
            merged.append([s,e])
        else:
            merged[-1][1] = max(merged[-1][1], e)
    return '\n'.join(f"{s} {e}" for s,e in merged)


def __main__():
    import sys
    data = sys.stdin.read()
    result = solve(data)
    if result is None:
        return
    sys.stdout.write(str(result))

if __name__ == '__main__':
    __main__()

