string solve(const string& data){
    istringstream ss(data); int n; if(!(ss>>n)) return "";
    vector<pair<long long,long long>> iv(n); for(int i=0;i<n;i++) ss>>iv[i].first>>iv[i].second;
    sort(iv.begin(), iv.end());
    vector<pair<long long,long long>> res;
    for(auto [s,e]: iv){ if(res.empty() || s>res.back().second) res.push_back({s,e}); else res.back().second=max(res.back().second,e); }
    stringstream out; for(size_t i=0;i<res.size();i++){ out<<res[i].first<<" "<<res[i].second; if(i+1<res.size()) out<<'\n'; }
    return out.str();
}


int main() {
    std::ostringstream ss;
    ss << std::cin.rdbuf();
    std::string input = ss.str();
    std::string output = solve(input);
    std::cout << output;
    return 0;
}

