import java.io.*;
import java.nio.charset.StandardCharsets;

public class Main {
static class Solution {
    public String solve(String data){
        String[] p=data.trim().split("\\s+");
        if(p.length==0) return "";
        int idx=0; int n=Integer.parseInt(p[idx++]);
        long[][] iv=new long[n][2];
        for(int i=0;i<n;i++){ iv[i][0]=Long.parseLong(p[idx++]); iv[i][1]=Long.parseLong(p[idx++]); }
        java.util.Arrays.sort(iv, java.util.Comparator.comparingLong(a->a[0]));
        java.util.List<long[]> res=new java.util.ArrayList<>();
        for(long[] seg: iv){ if(res.isEmpty() || seg[0]>res.get(res.size()-1)[1]) res.add(new long[]{seg[0],seg[1]}); else res.get(res.size()-1)[1]=Math.max(res.get(res.size()-1)[1], seg[1]); }
        StringBuilder sb=new StringBuilder();
        for(int i=0;i<res.size();i++){ sb.append(res.get(i)[0]).append(' ').append(res.get(i)[1]); if(i+1<res.size()) sb.append('\n'); }
        return sb.toString();
    }
}


    public static void main(String[] args) throws Exception {
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        InputStream in = System.in;
        byte[] buf = new byte[8192];
        int n;
        while ((n = in.read(buf)) != -1) {
            baos.write(buf, 0, n);
        }
        String input = baos.toString(StandardCharsets.UTF_8);
        Solution sol = new Solution();
        String output = sol.solve(input);
        if (output != null) {
            System.out.print(output);
        }
    }
}

