#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_INPUT (1 << 20)

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
typedef struct { long long s,e; } Interval;
int cmp(const void* a,const void* b){ long long d=((Interval*)a)->s - ((Interval*)b)->s; return d<0?-1:(d>0?1:0); }
char* solve(const char* data){
    char* copy = strdup(data);
    const char* delim = " \n\t";
    char* tok = strtok(copy, delim);
    if(!tok){ free(copy); return strdup(""); }
    int n = atoi(tok);
    Interval* iv = malloc(sizeof(Interval)*n);
    for(int i=0;i<n;i++){ tok = strtok(NULL, delim); iv[i].s = atoll(tok); tok = strtok(NULL, delim); iv[i].e = atoll(tok); }
    qsort(iv, n, sizeof(Interval), cmp);
    Interval* res = malloc(sizeof(Interval)*n); int m=0;
    for(int i=0;i<n;i++){
        if(m==0 || iv[i].s > res[m-1].e) res[m++] = iv[i];
        else if(iv[i].e > res[m-1].e) res[m-1].e = iv[i].e;
    }
    size_t buf = 32*m + 1; char* out = malloc(buf); size_t pos=0;
    for(int i=0;i<m;i++){ pos += sprintf(out+pos, "%lld %lld%s", res[i].s, res[i].e, (i+1<m)?"\n":""); }
    free(copy); free(iv); free(res);
    return out;
}


int main() {
    char *input = (char *)malloc(MAX_INPUT);
    if (!input) return 1;
    size_t len = fread(input, 1, MAX_INPUT - 1, stdin);
    input[len] = '\0';
    char *output = solve(input);
    if (output) {
        fputs(output, stdout);
        free(output);
    }
    free(input);
    return 0;
}
